module RefModule(
  input [7:0] a,
  input [7:0] b,
  input select,
  output reg led
);reg [7:0] result;
  wire [7:0] _tap_a = a & {8{1'b1}};


  always @(*) begin
    if (select == 1'b0) begin
      result = a;
    end else begin
      result = b;
    end
  end

  assign led = result[7];

endmodule
